import { useState, useCallback, useRef, useEffect } from 'react';
import {
  Tabs,
  Tab,
  TabTitleText,
  Button,
  Tooltip,
} from '@patternfly/react-core';
import { TimesIcon, PlusIcon, FolderOpenIcon } from '@patternfly/react-icons';
import type { Project } from '../state/store';

interface TabBarProps {
  projects: Project[];
  activeProjectId: string;
  onSelect: (projectId: string) => void;
  onClose: (projectId: string) => void;
  onAdd: () => void;
  onReorder?: (order: string[]) => void;
}

export function TabBar({
  projects,
  activeProjectId,
  onSelect,
  onClose,
  onAdd,
}: TabBarProps) {
  const [draggedId, setDraggedId] = useState<string | null>(null);
  const tabsRef = useRef<HTMLDivElement>(null);

  // Focus management after tab changes
  useEffect(() => {
    if (tabsRef.current && activeProjectId) {
      const activeTab = tabsRef.current.querySelector(`[data-tab-id="${activeProjectId}"]`);
      if (activeTab instanceof HTMLElement) {
        activeTab.focus();
      }
    }
  }, [activeProjectId]);

  const handleSelect = useCallback(
    (_event: React.MouseEvent<HTMLElement>, eventKey: string | number) => {
      if (typeof eventKey === 'string') {
        onSelect(eventKey);
      }
    },
    [onSelect]
  );

  const handleClose = useCallback(
    (event: React.MouseEvent<HTMLButtonElement>, projectId: string) => {
      event.stopPropagation();
      onClose(projectId);
    },
    [onClose]
  );

  const handleDragStart = useCallback((e: React.DragEvent, projectId: string) => {
    setDraggedId(projectId);
    e.dataTransfer.effectAllowed = 'move';
    e.dataTransfer.setData('text/plain', projectId);
  }, []);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  }, []);

  const handleDrop = useCallback(
    (e: React.DragEvent, targetId: string) => {
      e.preventDefault();
      const sourceId = e.dataTransfer.getData('text/plain');
      if (sourceId && sourceId !== targetId) {
        // TODO: Implement reorder when connected to state
        console.log('Reorder:', sourceId, '->', targetId);
      }
      setDraggedId(null);
    },
    []
  );

  const handleDragEnd = useCallback(() => {
    setDraggedId(null);
  }, []);

  // Empty state when no projects
  if (projects.length === 0) {
    return (
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          padding: '8px 16px',
          background: 'var(--pf-t--global--background--color--secondary--default)',
          borderBottom: '1px solid var(--pf-t--global--border--color--default)',
        }}
      >
        <Button
          variant="link"
          icon={<FolderOpenIcon />}
          onClick={onAdd}
        >
          Open a project to get started
        </Button>
      </div>
    );
  }

  return (
    <div ref={tabsRef} style={{ position: 'relative' }}>
      <Tabs
        activeKey={activeProjectId}
        onSelect={handleSelect}
        aria-label="Project tabs"
        role="region"
        isOverflowHorizontal={{ showTabCount: true }}
      >
        {projects.map((project) => (
          <Tab
            key={project.id}
            eventKey={project.id}
            data-tab-id={project.id}
            aria-label={`${project.name} tab`}
            title={
              <div
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px',
                }}
                draggable
                onDragStart={(e) => handleDragStart(e, project.id)}
                onDragOver={handleDragOver}
                onDrop={(e) => handleDrop(e, project.id)}
                onDragEnd={handleDragEnd}
              >
                <TabTitleText>{project.name}</TabTitleText>
                {projects.length > 1 && (
                  <Tooltip content="Close tab">
                    <Button
                      variant="plain"
                      aria-label={`Close ${project.name}`}
                      onClick={(e) => handleClose(e as React.MouseEvent<HTMLButtonElement>, project.id)}
                      style={{
                        padding: '2px',
                        minWidth: 'auto',
                        opacity: draggedId === project.id ? 0.5 : 1,
                      }}
                    >
                      <TimesIcon />
                    </Button>
                  </Tooltip>
                )}
              </div>
            }
            style={{
              opacity: draggedId === project.id ? 0.5 : 1,
              transition: 'opacity 0.2s',
            }}
          />
        ))}
      </Tabs>

      {/* Add tab button */}
      <div
        style={{
          position: 'absolute',
          right: '8px',
          top: '50%',
          transform: 'translateY(-50%)',
        }}
      >
        <Tooltip content="Open new project">
          <Button
            variant="plain"
            aria-label="Add project"
            onClick={onAdd}
            icon={<PlusIcon />}
          />
        </Tooltip>
      </div>
    </div>
  );
}

